// kaya wire vocabulary. Generated by kaya-bindgen from kaya::spec — do not edit.
//
// Records are {u32 size, u16 kind, u16 flags}, body, padded to 8,
// little-endian. Values accept Go bool, int64, float64, and string,
// mapped to the kaya value types; keys in paths likewise.
package kaya

import (
	"encoding/binary"
	"math"
)

const (
	ValueBool = 1
	ValueI64 = 2
	ValueF64 = 3
	ValueStr = 4
	KindColumn = 1
	KindButton = 2
	KindLabel = 3
	PropText = 1
	SourceConst = 0
	SourceSignal = 1
	SourceElement = 2
	OccurrencePad = 0
	OccurrenceButtonClicked = 1
	txCreateSignal = 1
	txWriteSignal = 2
	txCreateWidget = 3
	txSetProperty = 4
	txAddChild = 5
	txMount = 6
	txCreateCollection = 7
	txCollectionInsert = 8
	txCollectionUpdate = 9
	txCollectionRemove = 10
	txCreateFor = 11
	txCreateWhen = 12
	txTemplateEnd = 13
	applyCreate = 1
	applySetProp = 2
	applyAddChild = 3
	applyMount = 4
	applyDestroy = 5
	occButtonClicked = 1
)

func pad8(b []byte) []byte {
	for len(b)%8 != 0 {
		b = append(b, 0)
	}
	return b
}

// encodeValue appends one kaya value; values self-pad to 8 because
// they concatenate inside record bodies.
func encodeValue(b []byte, v any) []byte {
	switch x := v.(type) {
	case bool:
		b = binary.LittleEndian.AppendUint32(b, ValueBool)
		b = binary.LittleEndian.AppendUint32(b, 1)
		if x {
			b = append(b, 1)
		} else {
			b = append(b, 0)
		}
	case int:
		return encodeValue(b, int64(x))
	case int64:
		b = binary.LittleEndian.AppendUint32(b, ValueI64)
		b = binary.LittleEndian.AppendUint32(b, 8)
		b = binary.LittleEndian.AppendUint64(b, uint64(x))
	case float64:
		b = binary.LittleEndian.AppendUint32(b, ValueF64)
		b = binary.LittleEndian.AppendUint32(b, 8)
		b = binary.LittleEndian.AppendUint64(b, math.Float64bits(x))
	case string:
		b = binary.LittleEndian.AppendUint32(b, ValueStr)
		b = binary.LittleEndian.AppendUint32(b, uint32(len(x)))
		b = append(b, x...)
	default:
		panic("kaya: value must be bool, int64, float64, or string")
	}
	return pad8(b)
}

// encodePath appends a key path: {u32 count, u32 reserved, count values}.
func encodePath(b []byte, keys []any) []byte {
	b = binary.LittleEndian.AppendUint32(b, uint32(len(keys)))
	b = binary.LittleEndian.AppendUint32(b, 0)
	for _, k := range keys {
		b = encodeValue(b, k)
	}
	return b
}

func beginRecord(kind uint16) []byte {
	b := make([]byte, 0, 64)
	b = append(b, 0, 0, 0, 0)
	b = binary.LittleEndian.AppendUint16(b, kind)
	return append(b, 0, 0)
}

func endRecord(b []byte) []byte {
	b = pad8(b)
	binary.LittleEndian.PutUint32(b, uint32(len(b)))
	return b
}

// TxCreateSignal: Create a signal holding `initial`.
func TxCreateSignal(signalId uint64, initial any) []byte {
	b := beginRecord(txCreateSignal)
	b = binary.LittleEndian.AppendUint64(b, signalId)
	b = encodeValue(b, initial)
	return endRecord(b)
}

